var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"하아, 하아, 하아……!","JPN":"はぁ、はぁ、はぁ……！","ENG":"*Huff* *Huff* *Huff…!*","TWN":"哈啊，哈啊，哈啊……！"},"stage":{"bg":"THEATER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L7_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"크윽, 머리가…! 방금 그 기억은 뭐지…? 꿈인가……?","JPN":"くうっ、頭が……！　今の記憶は何……？　夢……？","ENG":"Argh, my head...! That memory just now... Was it a dream...?","TWN":"咳，頭好疼……！剛才的記憶是怎麼回事……？是夢嗎……？"},"stage":{"bg":"THEATER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"아니야… 꿈이라기에는 너무나 선명해…….","JPN":"ううん……あんなに生々しかったんだ……とても夢とは……","ENG":"No... it felt too real to be a dream...","TWN":"不……這太清晰了，不像是夢……"},"stage":{"bg":"THEATER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"마지막에는 마치, 내가 스완이 된 것 같은 느낌이었어……. 어떻게 된 거지?","JPN":"最後にはまるで、私がスワンになったような感覚だった……これって、どういうこと……？","ENG":"And at the end, it felt like I was Swan. What does that even mean?","TWN":"最後感覺，好像我變成了史旺……這是怎麼回事？"},"stage":{"bg":"THEATER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"아직 제정신을 유지하고 계시는군요.","JPN":"まだ正気を保っていますね。","ENG":"So, your mind's still intact.","TWN":"你還保持著清醒的頭腦啊。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L12_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"……스완!","JPN":"……スワン！","ENG":"...Swan!","TWN":"……史旺！"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"뭐, 좋아요. 그래서 첫 각본은 어떠셨나요? 소감을 듣고 싶군요.","JPN":"まあ、いいでしょう。それで、最初の脚本はいかがでしたか？　感想をお聞かせ願います。","ENG":"Well then. How did you enjoy the first script? I'd love to hear your thoughts.","TWN":"嗯，好吧。那麼第一部劇本怎麼樣？我想聽聽你的感想。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"대체 저한테 무슨 짓을 한 거죠?","JPN":"いったい私に何をしたんですか？","ENG":"What did you do to me?","TWN":"到底對我做了什麼？"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"당신이 보여준 그 세계… 그건 단순한 환각 같은 게 아니었어요!","JPN":"あなたが見せた世界……あれはただの幻覚なんかじゃなかった！","ENG":"That world you showed me... It wasn't just some illusion!","TWN":"你所展示的那個世界……那並不僅僅是幻覺！"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L18_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"그건 당신의 과거인가요? 그렇다면, 그 세계는 정말로 당신이……?","JPN":"あれはあなたの過去なんですか？　じゃあ、あの世界は本当にあなたが……？","ENG":"Was that... your past? Then that world was really...?","TWN":"那是你的過去嗎？如果是的話，那個世界真的是你……？"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"말씀드렸을 텐데요, 노엘.","JPN":"言ったはずです、ノエル。","ENG":"I told you already, Noelle.","TWN":"我應該說過，洛艾兒。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 극장은 저의 완전 기억 능력이 클리파 차원의 허수 에너지를 통해 재구성된 공간.","JPN":"この劇場は、私の完全記憶能力がクリファ次元の虚数エネルギーによって再構築された空間。","ENG":"This theater is a space where my perfect memory ability is reconstructed by the Qlipha Dimension's Imaginary Energy.","TWN":"這個劇場是透過逆卡巴拉次元的虛數能量重構的空間，由我的完全記憶能力所創造。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이 마주했던 세계는 암군이 으스러뜨린 수많은 세계 중 하나랍니다.","JPN":"あなたが目にした世界は、暗君によって潰された多くの世界の1つです。","ENG":"The world you saw is just one of many shattered by the Ignorant Monarch.","TWN":"你所面對的世界只是暗君摧毀的無數世界之一。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"클리포트 게임에서 패배하여, 지금은 마왕의 클리파 차원에 귀속되어버린 세계죠.","JPN":"クリフォトゲームで敗北し、今は魔王のクリファ次元に囚われている世界です。","ENG":"It's a world that lost the Qliphoth Game... and now belongs to a Demon Lord's Qlipha Dimension.","TWN":"在逆卡巴拉遊戲中失敗，現在被歸屬于魔王的逆卡巴拉次元的世界。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"말도 안 돼…….","JPN":"そんな……","ENG":"No way...","TWN":"這不可能……"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"제가 봤던 그 세계에서… 당신은 수없이 많은 사람들을 죽였잖아요…….","JPN":"私が見たあの世界で……あなたは数えきれないほどの人を殺した……","ENG":"In the world I saw... you killed so many people...","TWN":"在我所見過的那個世界裡……你殺了無數的人……"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"설마, 다른 세계에서도 그런 짓을 반복해 온 건가요? 대체 어째서……?","JPN":"まさか、他の世界でも同じことを繰り返してきたんですか？　いったいどうして……？","ENG":"Don't tell me you've done the same thing in other worlds too? Why would you do that...?","TWN":"難道，在其他世界也重複做那種事嗎？到底為什麼……？"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L29_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"물론, 그들에게 천사 강림을 시도하게끔 유도하기 위해서였답니다.","JPN":"もちろん彼らに天使の降臨を試させるためです。","ENG":"Simple. To push them into attempting the descent of an angel.","TWN":"當然，是為了引導他們嘗試召喚天使降臨。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저는 무척이나 오랫동안 천사를 쫓아왔으니까요.","JPN":"私はとても長い間、天使を追ってきましたから。","ENG":"After all, I've spent a very long time chasing an angel.","TWN":"我追逐天使已經很久了。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 예정대로 그들은 실패하고 말았죠.","JPN":"そして予定どおり彼らは失敗してしまったのです。","ENG":"As expected, they failed in the end.","TWN":"而且如預料的那樣，他們還是失敗了。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L32_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"천사 강림이라고요?","JPN":"天使の降臨……？","ENG":"Descent of an angel?","TWN":"天使降臨嗎？"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신도 그 세계의 결말을 지켜보았으니, 알고 있을 텐데요?","JPN":"あなたもあの世界の結末を見届けたのだから、もうおわかりでしょう。","ENG":"You witnessed how that world ended. So you should already know.","TWN":"你也見證了那個世界的結局，應該知道吧？"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그자들은 인류의 구원을 원했습니다. 그리고 그 수단으로써 신성을 이용하려고 했어요.","JPN":"彼らは人類の救済を求めた。そしてその手段として、神聖を利用しようとしました。","ENG":"They sought salvation for humanity... and tried to use the Divinity as their means.","TWN":"他們希望拯救人類，並試圖利用神性作為手段。"},"stage":{"bg":"SS_DELTA_02","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"신성의 찌꺼기에 불과하지만, 그들은 변이 인자를 통해, 다른 존재가 되길 바랐으니까요.","JPN":"神聖の残りかすに過ぎないとはいえ、彼らは変異ファクターを通して別の存在になることを願った。","ENG":"It was nothing but a residue of the Divinity, but they still clung to the hope of becoming something more through the mutation factor.","TWN":"雖然只是神聖的殘渣，但他們透過變異因數，希望成為其他存在。"},"stage":{"bg":"SS_DELTA_02","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그 대가로 그들은 수많은 이들의 목숨을 지불하고 말았죠.","JPN":"数多の人類の命と引き換えに。","ENG":"And in exchange, they paid with countless lives.","TWN":"作為代價，他們付出了無數人的生命。"},"stage":{"bg":"SS_DELTA_02","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……그럼에도 그들은 끝내 실패하고 말았습니다.","JPN":"……それでも彼らの努力は結局、成功に繋がりませんでした。","ENG":"...Yet in the end, they still failed.","TWN":"……即便如此，他們最後還是失敗了。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"애초에 인간의 몸으로 뱀의 길을 따라, 신성에 다다르는 것은 불가능에 가까운 일이니까요.","JPN":"そもそも人間の身でありながら蛇の道を進み、神聖に至ることは不可能なのです。","ENG":"From the beginning, reaching the Divinity by following the snake's path in a human body was next to impossible.","TWN":"本來以人類的身體沿著蛇之路，接近神性幾乎是不可能的事。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 당신은 다릅니다.","JPN":"しかしあなたは違います。","ENG":"But you're different.","TWN":"但是你不一樣。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"현실개변력의 근원에 가장 가까운, 오염되지 않은 순수한 신성…….","JPN":"現実改変力の根源に最も近く、穢れていない純粋な神聖……","ENG":"You embody pure, untainted Divinity, closest to the very origin of the Counter Reality Force...","TWN":"最接近現實改變力的根源，未被污染的純粹神聖……"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"세피로트 나무로부터 분리된 당신은 신성 그 자체가 검의 길을 따라, 인간으로 강림한 존재.","JPN":"セフィロトから分かれたあなたは、神聖そのものが剣の道を進み、人間として降臨した存在。","ENG":"Separated from the Tree of Sephiroth, you are a Divinity descended into human form, brought into this world through the path of the sword.","TWN":"從生命樹分離出來的你，神聖的存在本身沿著劍的道路，降臨為人類的存在。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"추정건대, 당신이야 말로 제가 줄곧 찾아왔던 천사라고 할 수 있겠죠.","JPN":"思うに、あなたこそが私がずっと探してきた天使と言えるでしょう。","ENG":"If I had to guess, you're the very angel I've been searching for all this time.","TWN":"推測起來，你才是我一直在尋找的天使吧。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"저는…….","JPN":"私は……","ENG":"I...","TWN":"我……"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L50_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"저는 제가 당신이 말하는 것처럼 대단한 존재라고 생각하지 않아요…….","JPN":"私は自分が、あなたの言うようなすごい存在だとは思いません……","ENG":"I don't think I'm anything as grand as what you claim...","TWN":"我並不認為自己像你說的那樣了不起……"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"그리고 제가 당신 말대로… 그 대단한 천사님이라고 해도…….","JPN":"そして私があなたの言う、そのすごい天使だったとしても……","ENG":"Even if I really am that great angel you claim I am...","TWN":"而且即使我像你說的那樣……是那位了不起的天使……"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"당신 같이 이기적인 사람은 절대 도와주지 않을 거예요……!","JPN":"あなたみたいに自分しか知らない人は、絶対手伝いません……！","ENG":"I'd never help someone as selfish as you...!","TWN":"像你這樣自私的人，我絕對不會幫忙的……！"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"알고 있어요. 당신의 무의식은 여전히 스스로를 인간이라고 굳게 믿고 있으니까요.","JPN":"そうでしょうね。あなたの無意識は、今もなお自分を人間と信じて疑っていませんから。","ENG":"I know. You subconsciously still believe you're just human.","TWN":"我知道，因為你的潛意識依然堅定地認為自己是人類。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"껍데기에 불과한 노엘 라이트라는 시골 소녀는 그렇게 생각하겠죠.","JPN":"殻に過ぎないノエル・ライトという田舎娘は、そのように思うのでしょう。","ENG":"That shell called Noelle Wright, the naive country girl would cling to that idea.","TWN":"那個名叫洛艾兒·萊特的鄉村少女會這麼認為吧。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"……큭.","JPN":"……くっ。","ENG":"...Krgh.","TWN":"……咳。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"}}}},{"id":"L7_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그렇기에 저는 당신을 이 극장에 가둔 겁니다.","JPN":"だから私はあなたをこの劇場に閉じ込めたのです。","ENG":"That's why I locked you inside this theater.","TWN":"所以我才把你困在這個劇場裡。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이곳은 당신을 무너트리기 위해, 준비한 심상 세계의 감옥이니까요.","JPN":"ここはあなたを壊すために用意した心象世界の檻ですから。","ENG":"This place is a prison of the mind, built to break you.","TWN":"這裡是為了擊垮你而準備的心象世界的牢獄。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"심상 세계의 감옥이라고요……?","JPN":"心象世界の檻……？","ENG":"A prison of the mind...?","TWN":"是心象世界的監獄嗎……？"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"첫 번째 각본을 경험해 봤으니, 이야기가 빠르겠군요.","JPN":"最初の脚本を経験しているので、理解しやすいと思います。","ENG":"You've already experienced the first script, so I won't need to explain much.","TWN":"既然已經體驗過第一個劇本了，那解釋起來就快了。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"인간의 기억은 자아를 구성하는 데 있어서 가장 중요한 요소랍니다.","JPN":"人間の記憶は自我を構成するにおいて、最も大事な要素です。","ENG":"Human memory is the most essential component in shaping self-awareness.","TWN":"人類的記憶是構成自我的最重要因素。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"과거와 현재, 어제와 오늘, 1분 전과 바로 지금…….","JPN":"過去と現在、昨日と今日、1分前と今……","ENG":"The past and the present, yesterday and today, even a minute ago and this very moment...","TWN":"過去與現在，昨天與今天，1分鐘前與現在……"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"기억이란, 매 순간순간 과거로 지나가 버리는 현재의 삶 속에서 연속성을 부여합니다.","JPN":"記憶とは、とめどなく過去へ流れてしまう現在の人生の中に連続性を生み出します。","ENG":"Memory grants continuity to our lives that slip into the past with every passing second.","TWN":"記憶為每一個過去的現在這個瞬間都賦予了連續性。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그리고 기억의 연속성이야말로, 인간이 스스로의 실존을 증명할 수 있는 유일한 수단이죠.","JPN":"そして記憶の連続性こそが、人間が自分の実存を証明できる唯一の手段なのです。","ENG":"And that continuity of memory is the only way humans can prove their own existence.","TWN":"而記憶的連續性，正是人類能夠證明自身存在的唯一手段。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"무, 무슨 말인지 모르겠어요.","JPN":"い、言ってる意味がわかりません。","ENG":"I-I don't understand.","TWN":"我不知道你在說什麼。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"갑자기 그게 뭐 어쨌다는 거죠?","JPN":"急にそれがどうしたと言うんですか？","ENG":"What does that even mean all of a sudden?","TWN":"突然說這個又能怎麼樣？"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"간단한 이야기랍니다. 노엘 라이트.","JPN":"簡単な話ですよ、ノエル・ライト。","ENG":"It's quite simple, Noelle Wright.","TWN":"這故事很簡單，洛艾兒·萊特。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"이 극장에서는 엘리시움 그림자들의 멘탈 프린팅의 원리를 모방할 수 있답니다.","JPN":"この劇場ではエリシウムシャドウたちのメンタル・プリンティング技術の原理を模倣することができます。","ENG":"I can imitate the Mental Printing method used by the Elysium Shadows in this theater.","TWN":"這個劇場模仿了愛樂組織暗影的智力複印原理，是我自己變奏的形式。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신이 현실의 법칙을 뒤틀고, 자신만의 작은 세계를 창조하였듯.","JPN":"あなたが現実の法則を捻じ曲げ、自分だけの小さな世界を作り出したように。","ENG":"Just as you twisted the laws of reality to create a world of your own...","TWN":"你扭曲了現實的法則，創造了屬於自己的小世界。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"저는 당신의 심상을 뒤틀고, 당신의 기억 속에 제 <color=#ffd34c>각본</color>을 새겨 넣을 수 있죠.","JPN":"私はあなたの心象を捻じ曲げ、あなたの記憶の中に私の<color=#ffd34c>脚本</color>を刻み込むことができます。","ENG":"I can twist your inner thoughts and inscribe my <color=#ffd34c>script</color> directly into your memory.","TWN":"我可以扭曲你的心象，在你的記憶中刻下我的<color=#ffd34c>劇本</color>。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그저 허구뿐인 당신의 삶에 계속해서 허구를 덧댈 뿐.","JPN":"ただ偽りだらけのあなたの人生に、偽りを加え続けるだけ。","ENG":"All I do is layer fiction upon the fiction that already defines your life.","TWN":"只是在你虛假的生活中不斷添加虛假的東西。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"하지만 그것만으로도 인간의 자아는 쉽게 무너져 버리고 만답니다.","JPN":"しかしそれだけで人間の自我は、いとも簡単に崩れてしまうのです。","ENG":"And yet, that alone is enough to shatter humans' self-awareness.","TWN":"但是僅憑這一點，人類的自我就會輕易崩潰。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"고, 고작 당신의 기억을 보게 된다고 자아를 잃게 된다고요……?","JPN":"あ、あなたの記憶を見ただけで自我を失う……？","ENG":"Y-you're saying... just witnessing your memories can make me lose my self-awareness...?","TWN":"只，只是看到你的記憶就會失去自我……？"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"그럴 리가 없잖아요……!","JPN":"そんなはずないでしょ……！","ENG":"That can't be true...!","TWN":"怎，怎麼可能……！"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"}}}},{"id":"L30_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"글쎄요, 한 번이나마 제 각본에 몰입해버린 당신이라면 짐작하고 있을 텐데요?","JPN":"どうでしょう。一度でも私の脚本にのめり込んでしまったあなたなら気づいているはずです。","ENG":"Oh? But if you've even once been drawn into my script, then you must suspect it by now.","TWN":"這個嘛，如果你曾經沉浸在我的劇本中，應該能猜到吧？"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"}}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"제가 단순히 허세를 부리고 있는 게 아니라는 걸.","JPN":"私の言葉が単なる脅しではないということを。","ENG":"That this isn't just some empty bluff.","TWN":"我並不是在虛張聲勢。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"그럼에도 변수 같은 건 없었어.","JPN":"それでも変数なんてものはなかった。","ENG":"Nothing changed. No variables.","TWN":"即便如此，也並沒有改變什麼。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_FILM"},{"id":"L34_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"결국… 이 세계에도 천사 같은 건 나타나지 않았어…….","JPN":"結局……この世界にも天使なんて現れなかった……","ENG":"In the end... no angel appeared in this world either…","TWN":"最後……這個世界上也沒有出現天使……"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"……크윽.","JPN":"……くうっ。","ENG":"...Kgh.","TWN":"……咳咳。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L38_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"종국에 극장이 당신의 자아를 완전히 삼켜버리게 되면.","JPN":"劇場があなたの自我を完全に飲み込んでしまえば最後。","ENG":"And when the theater finally consumes the last of your self-awareness...","TWN":"最後劇場會完全吞噬你的自我。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"당신은 노엘 라이트라는 껍데기에서 벗어나, 비로소 신성 에너지 그 자체로 되돌아가겠죠.","JPN":"あなたはノエル・ライトという殻から抜け出て、ようやく神聖エネルギーそのものに戻るのです。","ENG":"You'll shed the shell known as Noelle Wright and return to the pure Divinity energy.","TWN":"你將脫離洛艾兒·萊特這個軀殼，最後回歸為神聖能量本身。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"……세피라의 화신.","JPN":"……セフィラの化身。","ENG":"...Personification of Sephira.","TWN":"……生命樹的化身。"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"거, 거짓말! 제가 그런다고 당신의 말을 믿을 것 같아요?","JPN":"う、嘘！　そんなんで私があなたの言葉を信じると思いますか！","ENG":"Y-you're lying! You think I'd believe anything you say?","TWN":"這，這一定是騙人的！你以為我會相信你說的話嗎？"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"아, 아하! 그래……!","JPN":"そ、そうだ……！","ENG":"A-aha! That's right...!","TWN":"啊，啊哈！對了……！"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_PRIDE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"제가 없어졌다는 걸 알면 모두가 절 구하러 올 거예요!","JPN":"私がいなくなったことを知れば、みんな私を助けに来てくれるはずです！","ENG":"Once they realize I'm gone, everyone will come looking for me!","TWN":"如果大家知道我失蹤了，肯定會來找我的！"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"그때까지만… 그때까지만 버티면 돼요……!","JPN":"その時まで……その時まで耐えればいい……！","ENG":"I just have to hold on... just until then...!","TWN":"只要堅持到那時……只要堅持到那時就可以了……！"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"그럼, 분명히……!","JPN":"そうすれば、きっと……！","ENG":"Then surely...!","TWN":"那，肯定……！"},"stage":{"bg":"THEATER","bgm":"THEMA_CA_SWAN_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_MAIN_NPC_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"정말로 그렇게 생각하나요?","JPN":"本当にそう思いますか？","ENG":"Do you truly believe that?","TWN":"你真的這麼認為嗎？"},"stage":{"bg":"THEATER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"INTERN_MAIN_NPC_OFF","text":{"KOREA":"서, 설마……?","JPN":"ま、まさか……？","ENG":"N-no... it can't be...","TWN":"不，不會吧……？"},"stage":{"bg":"THEATER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"좋아요. 그럼, 두 번째 각본이 정해졌군요, 노엘 라이트.","JPN":"いいでしょう。これで2本目の脚本が決まりましたね、ノエル・ライト。","ENG":"Very well. The second script has now been written, Noelle Wright.","TWN":"好的，那麼，第二個劇本已經確定了，洛艾兒·萊特。"},"stage":{"bg":"THEATER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SWAN_SIX_NULL_NULL","text":{"KOREA":"두 번째 무대는 현실. <color=#ffd34c>당신</color>이 소실되어 버린 현실입니다.","JPN":"2本目の舞台は現実。<color=#ffd34c>あなた</color>が消失した現実です。","ENG":"The second stage is reality. The one <color=#ffd34c>you</color> have been erased from.","TWN":"第二個舞台是現實。<color=#ffd34c>你</color>已經消失的現實。"},"stage":{"bg":"THEATER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SIX_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};